import{_ as a,o as t,c as d,a2 as s}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"कॉन्फ़िगरेशन","description":"","frontmatter":{},"headers":[],"relativePath":"hi/guide/configuration.md","filePath":"hi/guide/configuration.md"}'),i={name:"hi/guide/configuration.md"};function o(c,e,n,r,l,p){return t(),d("div",null,[...e[0]||(e[0]=[s(`<h1 id="कॉन्फ़िगरेशन" tabindex="-1">कॉन्फ़िगरेशन <a class="header-anchor" href="#कॉन्फ़िगरेशन" aria-label="Permalink to &quot;कॉन्फ़िगरेशन&quot;">​</a></h1><p>Clearance उचित डिफ़ॉल्ट्स के साथ आता है, इसलिए <a href="/clearance-docs/hi/guide/installation.html">इंस्टॉलेशन</a> के बाद यह तुरंत काम करता है। जब आपको route prefix, middleware, प्रासंगिक मॉडल, या किसी अन्य सेटिंग को कस्टमाइज़ करना हो, तो config फाइल को publish करें।</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>यह <code>config/clearance.php</code> को publish करता है।</p><h2 id="कॉन्फ़िगरेशन-संदर्भ" tabindex="-1">कॉन्फ़िगरेशन संदर्भ <a class="header-anchor" href="#कॉन्फ़िगरेशन-संदर्भ" aria-label="Permalink to &quot;कॉन्फ़िगरेशन संदर्भ&quot;">​</a></h2><p>यह <code>config/clearance.php</code> में हर key के लिए निश्चित संदर्भ है। इन दस्तावेज़ों के अन्य पेज इस टेबल को दोहराने के बजाय यहीं लिंक करते हैं।</p><table tabindex="0"><thead><tr><th>Key</th><th>डिफ़ॉल्ट</th><th>उद्देश्य</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>सभी पैनल रूट्स के लिए URI prefix।</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td><code>clearance.access</code> से पहले सभी पैनल रूट्स पर लागू होता है।</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>access middleware द्वारा जांची जाने वाली अनुमति।</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>डिफ़ॉल्ट रूप से <code>auth.providers.users.model</code> का उपयोग करता है।</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>Users मॉड्यूल के लिए मास्टर स्विच (routes + Livewire components)।</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - वे मॉडल जो भूमिका-बंधन संदर्भ के रूप में कार्य कर सकते हैं।</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td><code>group-action</code> अनुमति नामकरण लागू करता है।</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>विभाजक (separator) कैरेक्टर - केवल <code>&#39;-&#39;</code> या <code>&#39;_&#39;</code>।</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td><code>config/auth.php</code> से auto-detect किए गए गार्ड्स को ओवरराइड करता है। खाली = सभी को auto-detect करें।</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>DB गार्ड्स को <code>auth.guards</code> में इंजेक्ट करते समय स्वीकार किए जाने वाले ड्राइवर।</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>पूरे पेज वाले components के लिए Blade layout। <code>null</code> = host ऐप का डिफ़ॉल्ट (<code>config(&#39;livewire.layout&#39;)</code>)।</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td><code>Registered</code> इवेंट पर Settings में कॉन्फ़िगर की गई डिफ़ॉल्ट भूमिका को स्वचालित रूप से असाइन करता है।</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>वैकल्पिक: <code>super_admin</code> एप्लिकेशन-व्यापी सभी Gate जांचों को bypass करता है।</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = <code>Flux::pro()</code> के माध्यम से auto-detect।</td></tr></tbody></table><h2 id="अनुमति-नामकरण-परंपरा" tabindex="-1">अनुमति नामकरण परंपरा <a class="header-anchor" href="#अनुमति-नामकरण-परंपरा" aria-label="Permalink to &quot;अनुमति नामकरण परंपरा&quot;">​</a></h2><p>अनुमतियों को <code>group-action</code> फॉर्मेट का पालन करना चाहिए:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p><code>enforce_naming_convention</code> के साथ प्रति environment इस enforcement को अक्षम करें:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Separator को boot के समय validate किया जाता है</p><p><code>naming_separator</code> वैल्यू इस config का एकमात्र हिस्सा है जो एक raw SQL fragment (अनुमतियों को group/sort करने के लिए) तक पहुंचता है, इसलिए केवल <code>-</code> या <code>_</code> ही स्वीकार किए जाते हैं।</p></div><h2 id="middleware-को-कस्टमाइज़-करना" tabindex="-1">Middleware को कस्टमाइज़ करना <a class="header-anchor" href="#middleware-को-कस्टमाइज़-करना" aria-label="Permalink to &quot;Middleware को कस्टमाइज़ करना&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Route names, prefix या middleware में बदलाव के बावजूद स्थिर रहते हैं - पूरी routes टेबल के लिए <a href="/clearance-docs/hi/guide/quick-start.html">क्विक स्टार्ट</a> देखें।</p><h2 id="संबंधित" tabindex="-1">संबंधित <a class="header-anchor" href="#संबंधित" aria-label="Permalink to &quot;संबंधित&quot;">​</a></h2><ul><li><a href="/clearance-docs/hi/guide/quick-start.html">क्विक स्टार्ट</a> - इन सेटिंग्स के लागू होने पर पैनल को माउंट करना</li><li><a href="/clearance-docs/hi/guide/publishing.html">एसेट्स पब्लिश करना</a> - translations को publish करना और <code>layout</code> key को समझना</li><li><a href="/clearance-docs/hi/features/guards.html">गार्ड</a> - <code>guards</code> और <code>allowed_guard_drivers</code> का उपयोग कैसे होता है</li><li><a href="/clearance-docs/hi/features/super-admin.html">सुपर एडमिन</a> - <code>super_admin_gate_bypass</code> कैसे काम करता है</li></ul>`,18)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
